import React, { useEffect, useState, useContext } from 'react';
import { useParams } from 'react-router-dom';
import apiRequest from '../services/api';
import { MapPin } from 'lucide-react';
import { Button } from '../components/ui/Button';
import BookingModal from '../components/BookingModal';
import { AuthContext } from '../context/AuthContext';

const PRIMARY_GREEN = '#012F01';

const PropertyPage = () => {
  const { id } = useParams();
  const [property, setProperty] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isBookingOpen, setBookingOpen] = useState(false);
  const { user } = useContext(AuthContext);

  useEffect(() => {
    const fetchProperty = async () => {
      setLoading(true);
      try {
        const data = await apiRequest(`/api/properties/${id}`);
        setProperty(data);
      } catch (err) {
        console.error('Failed to fetch property', err);
      } finally {
        setLoading(false);
      }
    };
    fetchProperty();
  }, [id]);

  if (loading) return <div className="p-8">Loading property...</div>;
  if (!property) return <div className="p-8">Property not found.</div>;

  return (
    <div className="max-w-4xl mx-auto p-6 space-y-6">
      <h1 className="text-3xl font-bold">{property.title}</h1>
      <p className="text-gray-600 flex items-center gap-1">
        <MapPin className="w-4 h-4" /> {property.location.address}
      </p>
      <img
        src={property.images?.[0] || 'https://picsum.photos/800/600'}
        alt={property.title}
        className="w-full h-96 object-cover rounded-lg"
      />
      <p>{property.description}</p>
      <p className="text-xl font-semibold">
        ${property.price} <span className="text-gray-500 text-sm">/ night</span>
      </p>
      <Button onClick={() => setBookingOpen(true)} style={{ backgroundColor: PRIMARY_GREEN }} className="text-white w-full sm:w-auto">
        Book now
      </Button>
      {user && (
        <BookingModal isOpen={isBookingOpen} onClose={() => setBookingOpen(false)} propertyId={id} onBooked={() => {}} />
      )}
    </div>
  );
};

export default PropertyPage;
